package pe.org.camaracomercioica.protestos.controller; import jakarta.validation.Valid; import lombok.RequiredArgsConstructor; import org.springframework.data.domain.*; import org.springframework.data.web.PageableDefault; import org.springframework.http.*; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; import pe.org.camaracomercioica.protestos.dto.*; import pe.org.camaracomercioica.protestos.model.EstadoSolicitud; import pe.org.camaracomercioica.protestos.service.SolicitudService; @RestController @RequestMapping("/api/solicitudes") @RequiredArgsConstructor public class SolicitudController {private final SolicitudService service;@PostMapping @ResponseStatus(HttpStatus.CREATED) SolicitudResponse crear(@Valid @RequestBody SolicitudRequest r,Authentication a){return service.crear(r,a.getName());}@GetMapping PageResponse<SolicitudResponse> listar(@RequestParam(required=false) EstadoSolicitud estado,@RequestParam(required=false) Long entidadId,@PageableDefault(size=20,sort="creadoEn",direction=Sort.Direction.DESC) Pageable p){return PageResponse.from(service.listar(estado,entidadId,p));}@GetMapping("/mis-solicitudes") PageResponse<SolicitudResponse> mias(Authentication a,@PageableDefault(size=20) Pageable p){return PageResponse.from(service.mias(a.getName(),p));}@PutMapping("/{id}/estado") SolicitudResponse estado(@PathVariable Long id,@Valid @RequestBody CambioEstadoRequest r,Authentication a){return service.cambiarEstado(id,r,a.getName());}}
